import axios from 'axios';
import toast from 'react-hot-toast';

// LOCAL:      uses /api  (proxied to localhost:5000 via package.json proxy)
// PRODUCTION: uses REACT_APP_API_URL from Netlify env vars
const API_BASE = process.env.REACT_APP_API_URL
  ? `${process.env.REACT_APP_API_URL}/api`
  : '/api';

const api = axios.create({
  baseURL: API_BASE,
  headers: { 'Content-Type': 'application/json' },
});

// Attach JWT on every request
api.interceptors.request.use((config) => {
  const token = localStorage.getItem('sms_token');
  if (token) config.headers.Authorization = `Bearer ${token}`;
  return config;
});

// Auto-logout on 401
api.interceptors.response.use(
  (res) => res,
  (error) => {
    if (error.response?.status === 401) {
      localStorage.removeItem('sms_token');
      localStorage.removeItem('sms_user');
      window.location.href = '/login';
    }
    return Promise.reject(error);
  }
);

// ── Auth ────────────────────────────────────────────────────────
export const authAPI = {
  login:          (data)       => api.post('/auth/login', data),
  me:             ()           => api.get('/auth/me'),
  register:       (data)       => api.post('/auth/register', data),
  changePassword: (data)       => api.put('/auth/change-password', data),
};

// ── Contacts ────────────────────────────────────────────────────
export const contactAPI = {
  getLists:        ()           => api.get('/contacts/lists'),
  createList:      (data)       => api.post('/contacts/lists', data),
  deleteList:      (id)         => api.delete(`/contacts/lists/${id}`),

  getContacts:     (params)     => api.get('/contacts', { params }),
  createContact:   (data)       => api.post('/contacts', data),
  updateContact:   (id, data)   => api.put(`/contacts/${id}`, data),
  deleteContact:   (id)         => api.delete(`/contacts/${id}`),

  importContacts:  (formData)   => api.post('/contacts/import', formData, {
    headers: { 'Content-Type': 'multipart/form-data' },
  }),
  getImportStatus: (id)         => api.get(`/contacts/import/${id}/status`),
};

// ── Campaigns ───────────────────────────────────────────────────
export const campaignAPI = {
  getAll:   (params) => api.get('/campaigns', { params }),
  getOne:   (id)     => api.get(`/campaigns/${id}`),
  create:   (data)   => api.post('/campaigns', data),
  launch:   (id)     => api.post(`/campaigns/${id}/launch`),
  pause:    (id)     => api.post(`/campaigns/${id}/pause`),
  delete:   (id)     => api.delete(`/campaigns/${id}`),
};

// ── Templates ───────────────────────────────────────────────────
export const templateAPI = {
  getAll:  ()           => api.get('/templates'),
  create:  (data)       => api.post('/templates', data),
  update:  (id, data)   => api.put(`/templates/${id}`, data),
  delete:  (id)         => api.delete(`/templates/${id}`),
};

// ── Sender Numbers ──────────────────────────────────────────────
export const senderAPI = {
  getAll:        ()       => api.get('/senders'),
  add:           (data)   => api.post('/senders', data),
  updateStatus:  (id, s)  => api.put(`/senders/${id}/status`, { status: s }),
  syncTwilio:    ()       => api.get('/senders/twilio/sync'),
  delete:        (id)     => api.delete(`/senders/${id}`),
};

// ── Analytics ───────────────────────────────────────────────────
export const analyticsAPI = {
  getDashboard: (days) => api.get('/analytics/dashboard', { params: { days } }),
  getCampaign:  (id)   => api.get(`/analytics/campaigns/${id}`),
};

// ── Admin ───────────────────────────────────────────────────────
export const adminAPI = {
  getUsers:       ()           => api.get('/admin/users'),
  updateUser:     (id, data)   => api.put(`/admin/users/${id}`, data),
  getAuditLogs:   ()           => api.get('/admin/audit-logs'),
  getQueueStats:  ()           => api.get('/admin/queue-stats'),
  getTwilioBalance: ()         => api.get('/admin/twilio-balance'),
};


export const messagesAPI = {
  getAll       : (params) => api.get('/messages',          { params }),
  getStats     : ()       => api.get('/messages/stats'),
  getOptOuts   : (params) => api.get('/messages/opt-outs', { params }),
  manualOptOut : (data)   => api.post('/messages/opt-out', data),
  manualOptIn  : (data)   => api.post('/messages/opt-in',  data),
  getIncoming  : (params) => api.get('/messages/incoming', { params }),
};

export default api;
